class RangeModule {
    Set<Double> intervals = new HashSet<>();

    public RangeModule() {
    }

    public void addRange(int left, int right) {
        intervals.add((double) left);
        intervals.add((double) right);
    }

    public boolean queryRange(int left, int right) {
        return intervals.contains((double) left) && intervals.contains((double) right);
    }

    public void removeRange(int left, int right) {
        intervals.remove((double) left);
        intervals.remove((double) right);
    }
}
